example.code:
-- Enable extension CREATE EXTENSION IF NOT EXISTS vector;
-- Create table with vector column CREATE TABLE documents ( id BIGSERIAL PRIMARY KEY, content TEXT NOT NULL, source VARCHAR(255), page INTEGER, category VARCHAR(100), embedding vector(1536), -- OpenAI dimension created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP );
-- Create HNSW index (recommended) CREATE INDEX ON documents USING hnsw (embedding vector_cosine_ops) WITH (m = 16, ef_construction = 64);
-- Or IVFFlat index (faster build, less accurate) CREATE INDEX ON documents USING ivfflat (embedding vector_cosine_ops) WITH (lists = 100); -- sqrt(n) for n rows

-- Set probes for IVFFlat (accuracy vs speed tradeoff) SET ivfflat.probes = 10; -- Default: 1
-- Set ef_search for HNSW SET hnsw.ef_search = 100; -- Default: 40
-- Partial index for filtered queries CREATE INDEX ON documents USING hnsw (embedding vector_cosine_ops) WHERE category = 'technical';
-- Vacuum and analyze after bulk inserts VACUUM ANALYZE documents;
-- Check index usage EXPLAIN ANALYZE SELECT * FROM documents ORDER BY embedding <=> '[...]'::vector LIMIT 10;

from pinecone import Pinecone, ServerlessSpec

# Initialize
pc = Pinecone(api_key="your-api-key")

# Create index
pc.create_index(
    name="documents",
    dimension=1536,
    metric="cosine",
    spec=ServerlessSpec(
        cloud="aws",
        region="us-east-1"
    )
)

# Connect to index
index = pc.Index("documents")

# Upsert vectors
index.upsert(
    vectors=[
        {
            "id": "doc1",
            "values": embedding,
            "metadata": {
                "text": "Document content...",
                "source": "file.pdf",
                "category": "technical"
            }
        }
    ],
    namespace="production"  -- Optional namespace
)

# Batch upsert
vectors = [
    {"id": f"doc{i}", "values": emb, "metadata": meta}
    for i, (emb, meta) in enumerate(zip(embeddings, metadatas))
]

# Upsert in batches of 100
for i in range(0, len(vectors), 100):
    batch = vectors[i:i+100]
    index.upsert(vectors=batch, namespace="production")

# Basic query
results = index.query(
    vector=query_embedding,
    top_k=10,
    include_metadata=True,
    namespace="production"
)

for match in results["matches"]:
    print(f"ID: {match['id']}, Score: {match['score']}")
    print(f"Metadata: {match['metadata']}")

# Filtered query
results = index.query(
    vector=query_embedding,
    top_k=10,
    filter={
        "category": {"$eq": "technical"},
        "$and": [
            {"page": {"$gte": 1}},
            {"page": {"$lte": 10}}
        ]
    },
    include_metadata=True,
)

# Hybrid search with sparse-dense
results = index.query(
    vector=dense_embedding,
    sparse_vector={
        "indices": [100, 200, 300],
        "values": [0.5, 0.3, 0.2]
    },
    top_k=10,
)

def select_db(corpus_size: int, managed: bool, has_postgres: bool,
              needs_graph: bool, scale_1b: bool) -> str:
    if corpus_size < 50_000 and not managed:
        return "chroma"  # Prototype
    if has_postgres and corpus_size < 5_000_000:
        return "pgvector"  # No new infra
    if needs_graph:
        return "weaviate"
    if scale_1b or managed:
        return "pinecone"
    return "qdrant"  # Default production self-hosted

from dataclasses import dataclass

@dataclass
class DBRequirements:
    corpus_vectors: int
    latency_ms_p95: int
    managed: bool
    has_postgres: bool
    needs_graph: bool
    needs_hybrid_native: bool
    team_size: int  # ops headcount

RECOMMENDATIONS = {
    "chroma":    {"max_vectors": 500_000, "managed": False, "graph": False},
    "pgvector":  {"max_vectors": 5_000_000, "managed": False, "graph": False},
    "qdrant":    {"max_vectors": 500_000_000, "managed": True, "graph": False},
    "weaviate":  {"max_vectors": 100_000_000, "managed": True, "graph": True},
    "pinecone":  {"max_vectors": 10_000_000_000, "managed": True, "graph": False},
    "milvus":    {"max_vectors": 10_000_000_000, "managed": False, "graph": False},
}

def recommend(req: DBRequirements) -> str:
    if req.has_postgres and req.corpus_vectors < 5_000_000:
        return "pgvector"
    if req.needs_graph:
        return "weaviate"
    if req.corpus_vectors > 500_000_000 or req.managed:
        return "pinecone"
    if req.corpus_vectors < 50_000:
        return "chroma"
    return "qdrant"

